#include<bits/stdc++.h>
#define LL long long
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 3e5+5;
string s;LL n,f[10],dp[N],ans;
int main(){
    //freopen("pareidolia.in","r",stdin);
    //freopen("pareidolia.out","w",stdout);
    cin>>s;n=s.size(),s=" "+s;
    for(int i=1;i<=n;i++){
        if(s[i]=='b')f[1]=i;
        if(s[i]=='e')f[6]=f[5],f[2]=f[1];
        if(s[i]=='s')f[4]=f[3],f[3]=f[2];
        if(s[i]=='i')f[5]=f[4];
        if(f[6])dp[i]=dp[f[6]-1]+f[6];
    }
    for(int i=1;i<=n;i++)ans+=dp[i];
    cout<<ans<<"\n";
    return 0;
}
